INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmmd6rjrd000213zy36lpbvfl', 'ABOUT', '{"body": "<h2>About NAGECO Libya</h2><p><strong>NAGECO Libya</strong> is a Libyan company committed to delivering reliable business solutions and professional services across multiple sectors. Our goal is to support companies and organizations with efficient, transparent, and high-quality services.</p><p>With a focus on professionalism and long-term partnerships, NAGECO Libya works to provide practical solutions that help businesses grow and operate more effectively in the Libyan market.</p><h3>Our Mission</h3><p>To deliver dependable services that create value for our clients and partners.</p><h3>Our Vision</h3><p>To become a trusted partner for businesses operating in Libya.</p><h3>Our Values</h3><p>Integrity, professionalism, efficiency, and commitment to excellence.</p>", "title": "About NAGECO"}', '', '', '2026-03-05 08:10:44.809', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmmd4f2at0008feae7l43nx62', 'HSE', '{"body": "<section class=\"hse-section\">\n  <div class=\"hse-container\">\n    <h2 class=\"hse-title\">Health, Safety, and Environment (HSE)</h2>\n    <p class=\"hse-text\">\n      Health, Safety, and Environment (HSE) at <strong>NAGECO</strong> is a core value embedded in all operations and activities. \n      The company is committed to ensuring a safe and healthy workplace for its employees, contractors, and stakeholders while minimizing environmental impact.\n    </p>\n    <p class=\"hse-text\">\n      <strong>NAGECO</strong> adopts international HSE standards and best practices, with a strong focus on risk management, continuous training, incident prevention, and environmental protection.\n    </p>\n    <p class=\"hse-text\">\n      Through a proactive HSE culture, <strong>NAGECO</strong> aims to achieve operational excellence and sustainable performance across all its geophysical exploration activities.\n    </p>\n  </div>\n</section>\n\n<style>\n  .hse-section {\n    background: linear-gradient(135deg, #f4f8fb, #eaf2f7);\n    padding: 60px 20px;\n    display: flex;\n    justify-content: center;\n  }\n\n  .hse-container {\n    max-width: 900px;\n    background: #ffffff;\n    padding: 40px 35px;\n    border-radius: 18px;\n    box-shadow: 0 8px 25px rgba(0, 0, 0, 0.08);\n    border-left: 6px solid #0b6b53;\n  }\n\n  .hse-title {\n    font-size: 32px;\n    font-weight: 700;\n    color: #0b2e4f;\n    margin-bottom: 20px;\n    line-height: 1.3;\n  }\n\n  .hse-text {\n    font-size: 17px;\n    line-height: 1.9;\n    color: #444;\n    margin-bottom: 18px;\n  }\n\n  .hse-text strong {\n    color: #0b6b53;\n  }\n\n  @media (max-width: 768px) {\n    .hse-container {\n      padding: 30px 20px;\n    }\n\n    .hse-title {\n      font-size: 26px;\n    }\n\n    .hse-text {\n      font-size: 16px;\n    }\n  }\n</style>", "title": "Health, Safety, and Environment (HSE)", "subtitle": "Health, Safety, and Environment (HSE)", "heroImageUrl": "/uploads/1774856024228-5fb565ef-0d25-483a-b83c-e697ee4857b7.JPG", "panelImageUrl": "/uploads/1773916864515-48e32b38-92ed-452a-ab50-23054ed6a288.JPG", "featureImageUrl": "/uploads/1774856009779-885793fe-070b-4511-b292-49f2382ae796.jpg", "galleryImageUrls": "/uploads/1774856009779-885793fe-070b-4511-b292-49f2382ae796.jpg"}', 'HSE', 'NAGECO HSE', '2026-03-30 08:08:57.598', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmmkapjer00003cdyb9mn5amq', 'HOME', '{"ctaLabel": "Contact Our Team", "heroTitle": "Empowering Growth and Innovation.", "heroSubtitle": "NAGECO Is a national company wholly owned by the National Oil Corporation (NOC) Libya.\nWe specialize in providing high-quality seismic and geophysical solutions to support oil and gas exploration and development."}', '', '', '2026-03-10 08:14:11.591', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmmkfwvbj000g3cdyb2oek46k', 'CAPABILITIES', '{"body": "NAGECO provides comprehensive seismic services designed to support energy exploration, resource evaluation, and subsurface research across North Africa and other operational regions. Our seismic capabilities combine advanced geophysical technologies with experienced field teams to deliver accurate, high-quality data that enables confident decision-making in exploration and development projects. Through disciplined operational planning, strong safety culture, and continuous technical improvement, NAGECO ensures that every seismic survey is executed with precision, efficiency, and reliability.\n\nOur seismic operations begin with careful survey preparation and acquisition planning. We work closely with clients to understand project objectives, geological context, and operational constraints in order to design field programs that maximize data quality and operational efficiency. This phase includes terrain assessment, logistics planning, equipment mobilization, crew organization, and HSE risk evaluation. By establishing a clear operational framework from the start, NAGECO ensures that seismic surveys proceed smoothly and meet both technical and regulatory requirements.\n\nDuring the acquisition phase, NAGECO deploys trained seismic crews equipped with modern recording systems and reliable field equipment. Our teams are experienced in operating in diverse environments, including deserts, remote terrains, and complex logistical settings. Field operations are carried out according to strict quality control procedures, ensuring that data acquisition parameters are continuously monitored and optimized. This real-time quality assurance allows our teams to identify and resolve operational challenges quickly, maintaining the integrity and consistency of the collected seismic data.\n\nNAGECO places strong emphasis on operational discipline and efficiency in the field. Our crews follow structured workflows that coordinate survey layout, source operations, receiver deployment, and recording processes in a synchronized manner. By maintaining well-organized field logistics and clear communication between operational units, we ensure that surveys progress safely and efficiently while minimizing downtime. This structured approach allows NAGECO to maintain productivity even in demanding operational environments.\n\nHealth, Safety, and Environmental protection are central to every seismic project conducted by NAGECO. We implement strict HSE standards that guide all aspects of field operations, from crew training and equipment handling to environmental protection and risk management. Our teams are trained to operate responsibly within local communities and natural environments, ensuring that seismic activities are conducted safely and with minimal environmental impact. This commitment to safety not only protects our personnel but also reinforces the reliability and professionalism expected by our clients.\n\nData quality remains a core priority throughout the seismic survey lifecycle. NAGECO integrates systematic quality control processes to verify acquisition parameters, monitor recording performance, and maintain consistency across the entire survey area. Our field specialists continuously evaluate the collected data to ensure that it meets the required technical standards and client specifications. By combining advanced monitoring tools with experienced interpretation oversight, we provide dependable seismic datasets ready for further processing and interpretation.\n\nIn addition to field acquisition, NAGECO supports clients through coordination with geophysical analysts and project managers who oversee operational progress and technical performance. This integrated approach ensures that each survey contributes meaningful subsurface information that can support geological interpretation, reservoir characterization, and exploration strategy. Our teams work collaboratively with client representatives to ensure transparency, communication, and alignment with project goals.\n\nThrough experience, technical expertise, and strong operational discipline, NAGECO has established itself as a reliable partner in geophysical exploration. Our seismic services are built on a foundation of professionalism, technical accuracy, and commitment to client success. By delivering dependable field execution and consistent data quality, NAGECO contributes to the discovery and responsible development of subsurface resources.\n\nWith a forward-looking approach and a dedication to continuous improvement, NAGECO remains committed to advancing seismic field operations and supporting the evolving needs of the energy and geoscience industries. Our mission is to provide trusted seismic services that transform complex subsurface environments into clear, actionable insights for our clients.\n", "title": ""}', '', '', '2026-03-10 10:06:46.406', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmncwvffu000e7b4nmdzwdxxf', 'CONTACT', '{"title": "Contact", "emails": "info@nageco.com", "phones": "+218 91 000 0000", "address": "Libya", "subtitle": "<p class=\"contact-intro\">\nWe are committed to delivering responsive and reliable support to our partners and clients. From technical consultations to project collaboration, NAGECO’s experts are available to provide guidance, solutions, and field-ready expertise. Get in touch with us and let’s move your project forward with confidence.\n</p>", "whatsapp": "+218 91 000 0000"}', '', '', '2026-03-30 08:21:42.936', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmmkh82qa0000szp7ejrp6hv7', 'SERVICES', '{"body": "<div style=\"max-width:1200px;margin:0 auto;font-family:Arial,Helvetica,sans-serif;color:#0f172a;\">\n\n  <div style=\"margin-bottom:30px;\">\n    <h2 style=\"font-size:44px;line-height:1.1;margin:0 0 12px 0;font-weight:800;letter-spacing:-1px;\">\n      <span style=\"color:#111827;\">OUR</span>\n      <span style=\"color:#2f6fd6;\"> SERVICES</span>\n    </h2>\n    <p style=\"font-size:18px;line-height:1.8;color:#475569;max-width:850px;margin:0;\">\n      NAGECO delivers integrated geophysical and operational services designed to support seismic exploration,\n      field execution, data quality, imaging, and HSE performance across complex environments.\n    </p>\n  </div>\n\n  <div style=\"display:flex;flex-direction:column;gap:18px;\">\n\n    <div style=\"background:linear-gradient(90deg,#1456c8 0%,#6ec1e4 100%);border-radius:24px;padding:22px 26px;box-shadow:0 10px 25px rgba(20,86,200,0.12);\">\n      <h3 style=\"margin:0 0 8px 0;color:#ffffff;font-size:28px;font-weight:800;\">Seismic Survey Planning and Design</h3>\n      <p style=\"margin:0;color:rgba(255,255,255,0.92);font-size:16px;line-height:1.8;\">\n        We develop survey concepts and acquisition plans tailored to geological objectives, terrain conditions,\n        operational constraints, and project timelines to ensure efficient and technically robust field execution.\n      </p>\n    </div>\n\n    <div style=\"background:linear-gradient(90deg,#1456c8 0%,#6ec1e4 100%);border-radius:24px;padding:22px 26px;box-shadow:0 10px 25px rgba(20,86,200,0.12);\">\n      <h3 style=\"margin:0 0 8px 0;color:#ffffff;font-size:28px;font-weight:800;\">Seismic Data Acquisition (Land &amp; Marine)</h3>\n      <p style=\"margin:0;color:rgba(255,255,255,0.92);font-size:16px;line-height:1.8;\">\n        Our field teams carry out reliable seismic acquisition campaigns using disciplined workflows, modern equipment,\n        and experienced crews to deliver high-quality subsurface data across a wide range of operating environments.\n      </p>\n    </div>\n\n    <div style=\"background:linear-gradient(90deg,#1456c8 0%,#6ec1e4 100%);border-radius:24px;padding:22px 26px;box-shadow:0 10px 25px rgba(20,86,200,0.12);\">\n      <h3 style=\"margin:0 0 8px 0;color:#ffffff;font-size:28px;font-weight:800;\">Field Processing</h3>\n      <p style=\"margin:0;color:rgba(255,255,255,0.92);font-size:16px;line-height:1.8;\">\n        We apply field-based processing and preliminary data checks to improve operational visibility, support fast\n        decision-making, and maintain acquisition consistency throughout the survey lifecycle.\n      </p>\n    </div>\n\n    <div style=\"background:linear-gradient(90deg,#1456c8 0%,#6ec1e4 100%);border-radius:24px;padding:22px 26px;box-shadow:0 10px 25px rgba(20,86,200,0.12);\">\n      <h3 style=\"margin:0 0 8px 0;color:#ffffff;font-size:28px;font-weight:800;\">Seismic QC</h3>\n      <p style=\"margin:0;color:rgba(255,255,255,0.92);font-size:16px;line-height:1.8;\">\n        Continuous quality control is integrated into every phase of acquisition to verify parameters, monitor data\n        integrity, reduce operational errors, and ensure technical compliance with project specifications.\n      </p>\n    </div>\n\n    <div style=\"background:linear-gradient(90deg,#1456c8 0%,#6ec1e4 100%);border-radius:24px;padding:22px 26px;box-shadow:0 10px 25px rgba(20,86,200,0.12);\">\n      <h3 style=\"margin:0 0 8px 0;color:#ffffff;font-size:28px;font-weight:800;\">Velocity Analysis and Imaging</h3>\n      <p style=\"margin:0;color:rgba(255,255,255,0.92);font-size:16px;line-height:1.8;\">\n        Our workflows support accurate velocity model development and seismic imaging to enhance structural definition,\n        improve interpretability, and provide clearer subsurface understanding for exploration teams.\n      </p>\n    </div>\n\n    <div style=\"background:linear-gradient(90deg,#1456c8 0%,#6ec1e4 100%);border-radius:24px;padding:22px 26px;box-shadow:0 10px 25px rgba(20,86,200,0.12);\">\n      <h3 style=\"margin:0 0 8px 0;color:#ffffff;font-size:28px;font-weight:800;\">Seismic Data Processing</h3>\n      <p style=\"margin:0;color:rgba(255,255,255,0.92);font-size:16px;line-height:1.8;\">\n        We support the transformation of acquired seismic records into reliable datasets through structured processing\n        sequences designed to improve signal quality, reduce noise, and prepare data for interpretation.\n      </p>\n    </div>\n\n    <div style=\"background:linear-gradient(90deg,#1456c8 0%,#6ec1e4 100%);border-radius:24px;padding:22px 26px;box-shadow:0 10px 25px rgba(20,86,200,0.12);\">\n      <h3 style=\"margin:0 0 8px 0;color:#ffffff;font-size:28px;font-weight:800;\">Integrated Interpretation Support</h3>\n      <p style=\"margin:0;color:rgba(255,255,255,0.92);font-size:16px;line-height:1.8;\">\n        NAGECO contributes to integrated subsurface understanding by supporting interpretation teams with structured\n        data outputs, technical coordination, and operational insight gathered throughout field execution.\n      </p>\n    </div>\n\n    <div style=\"background:linear-gradient(90deg,#1456c8 0%,#6ec1e4 100%);border-radius:24px;padding:22px 26px;box-shadow:0 10px 25px rgba(20,86,200,0.12);\">\n      <h3 style=\"margin:0 0 8px 0;color:#ffffff;font-size:28px;font-weight:800;\">HSE Management</h3>\n      <p style=\"margin:0;color:rgba(255,255,255,0.92);font-size:16px;line-height:1.8;\">\n        Safety is embedded in every operation. Our HSE approach covers risk assessment, crew awareness, environmental\n        protection, and strict field compliance to ensure safe and responsible project delivery.\n      </p>\n    </div>\n\n  </div>\n\n</div>", "title": "", "heroImageUrl": "/uploads/1773139484267-9b045d4e-d725-4b21-8519-d6e365d03239.JPG", "featureImageUrl": "/uploads/1773139506230-ece96c26-54cc-4ad5-af77-8382c00168db.JPG"}', '', '', '2026-03-10 11:03:48.938', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmmkiu5r50000kaovgpryfost', 'INDUSTRIES', '{"body": "NAGECO provides geophysical and seismic services that support a wide range of industries requiring accurate subsurface information and reliable field operations. Our experience in seismic acquisition, data management, and operational execution allows us to assist clients working in complex environments and challenging terrains. By combining field expertise with disciplined workflows, we help organizations obtain the data and insights needed for confident technical and operational decisions.\n\nIn the oil and gas industry, NAGECO supports exploration and development activities by delivering high-quality seismic acquisition services and dependable field execution. Our teams work closely with operators and exploration companies to collect subsurface data that helps identify geological structures, reduce exploration risk, and guide drilling and reservoir evaluation strategies.\n\nFor energy infrastructure projects, NAGECO contributes geophysical data that supports the planning and development of pipelines, facilities, and large-scale energy installations. Reliable subsurface understanding helps engineers evaluate ground conditions, optimize infrastructure placement, and minimize technical risks during construction and development.\n\nNAGECO also supports mining and mineral exploration programs by providing geophysical survey solutions that assist in identifying subsurface formations and geological structures associated with mineral resources. Our field operations help exploration teams collect the information necessary to guide resource evaluation and exploration planning.\n\nIn addition, our services contribute to environmental and geoscience studies that require reliable subsurface information. Government institutions, research organizations, and environmental programs benefit from geophysical data that supports groundwater assessment, geological mapping, and environmental monitoring initiatives.\n\nThrough operational reliability, technical expertise, and a strong commitment to safety, NAGECO works across multiple sectors where geophysical knowledge is essential. Our goal is to support industries that depend on accurate subsurface intelligence, disciplined field execution, and dependable geophysical solutions.", "title": "Industries", "heroImageUrl": "/uploads/1773142230481-9ae038b8-bb43-4a86-8939-07c5ee0421fb.JPG", "featureImageUrl": "/uploads/1773142166014-36fd3863-44d3-413b-8626-f1d604d01506.JPG"}', '', '', '2026-03-10 11:30:49.943', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmnbpzzrc000010g3oyr1pl9l', 'NEWS', '{"title": "News1", "subtitle": "News1"}', '', '', '2026-03-29 12:24:08.08', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmnd7hsec0000oroc1c9uy1d0', 'TERMS', '{"body": "<p>\nWelcome to the NAGECO website. By accessing or using this website, you agree to comply with and be bound by the following Terms and Conditions.\n</p>\n\n<p>\nAll content on this website, including text, graphics, logos, and materials, is the property of NAGECO and is protected by applicable intellectual property laws.\n</p>\n\n<p>\nYou may use this website for lawful purposes only and in a manner that does not infringe the rights of others.\n</p>\n\n<p>\nUnauthorized use of this website may result in legal action.\n</p>\n\n<p>\nNAGECO reserves the right to modify, suspend, or discontinue any part of the website at any time without prior notice.\n</p>\n\n<p>\nWe do not guarantee that the website will be uninterrupted, secure, or error-free.\n</p>\n\n<p>\nUsers are responsible for ensuring that any information or services obtained from this website meet their specific requirements.\n</p>\n\n<p>\nNAGECO shall not be liable for any direct, indirect, or consequential damages arising from the use of this website.\n</p>\n\n<p>\nThis website may include links to third-party websites for convenience; we do not endorse or take responsibility for their content.\n</p>\n\n<p>\nYou agree not to attempt to gain unauthorized access to any part of the website or its systems.\n</p>\n\n<p>\nAny misuse of the website, including introducing malicious code or attempting to disrupt services, is strictly prohibited.\n</p>\n\n<p>\nNAGECO reserves the right to restrict or terminate access to users who violate these terms.\n</p>\n\n<p>\nThese Terms and Conditions shall be governed by and interpreted in accordance with applicable laws.\n</p>\n\n<p>\nAny disputes arising from the use of this website shall be subject to the jurisdiction of competent courts.\n</p>\n\n<p>\nWe may update these Terms and Conditions at any time without prior notice.\n</p>\n\n<p>\nChanges will be effective immediately upon posting on this page.\n</p>\n\n<p>\nUsers are advised to review these terms periodically.\n</p>\n\n<p>\nYour continued use of the website constitutes acceptance of any revised terms.\n</p>\n\n<p>\nIf you do not agree with these Terms and Conditions, you should discontinue use of the website immediately.\n</p>\n\n ", "title": "Terms & Conditions"}', '', '', '2026-03-30 13:11:55.875', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
INSERT INTO public."PageContent" (id, key, "sectionsJson", "seoTitle", "seoDescription", "updatedAt", "createdById", "updatedById") VALUES ('cmnd7ij5s0002orockqnqfkw7', 'PRIVACY', '{"body": "<p>\nAt NAGECO, we are committed to protecting your privacy and ensuring the security of your personal information. \nThis Privacy Policy outlines how we collect, use, and safeguard your data when you visit our website or interact with our services.\n</p>\n\n<p>\nWe may collect personal information such as your name, email address, phone number, and company details when you voluntarily submit them through our contact forms or communications.\n</p>\n\n<p>\nThe information collected is used solely to respond to inquiries, provide services, improve user experience, and support our business operations.\n</p>\n\n<p>\nWe do not sell, rent, or share your personal information with third parties except where required by law or to fulfill contractual obligations.\n</p>\n\n<p>\nNAGECO implements appropriate technical and organizational measures to protect your data from unauthorized access, disclosure, or misuse.\n</p>\n\n<p>\nOur website may use cookies or similar technologies to enhance functionality and analyze website performance.\n</p>\n\n<p>\nYou have the right to request access to, correction of, or deletion of your personal data at any time.\n</p>\n\n<p>\nWe retain personal information only for as long as necessary to fulfill the purposes outlined in this policy.\n</p>\n\n<p>\nThird-party links on our website are provided for convenience; however, we are not responsible for their privacy practices.\n</p>\n\n<p>\nBy using our website, you consent to the terms of this Privacy Policy.\n</p>\n\n<p>\nWe reserve the right to update or modify this Privacy Policy at any time without prior notice.\n</p>\n\n<p>\nAny changes will be posted on this page and will take effect immediately upon publication.\n</p>\n\n<p>\nUsers are encouraged to review this policy periodically to stay informed of updates.\n</p>\n\n<p>\nIf you have any questions regarding this Privacy Policy, please contact us through our official communication channels.\n</p>\n\n<p>\nWe are committed to maintaining transparency and trust in all our data handling practices.\n</p>\n\n<p>\nYour continued use of the website signifies your acceptance of any changes made to this policy.\n</p>\n\n<p>\nThis policy applies to all visitors, users, and stakeholders interacting with NAGECO online platforms.\n</p>\n\n<p>\nWe strive to ensure that your personal data is handled responsibly and securely at all times.\n</p>\n\n<p>\nProtecting your information is an essential part of our commitment to excellence and integrity.\n</p>\n\n ", "title": "Privacy Policy"}', '', '', '2026-03-30 13:12:02.176', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3');
