INSERT INTO public."Tender" (id, title, slug, summary, status, "publishedAt", "createdAt", "updatedAt", "createdById", "updatedById", "documentUrls", "imageUrls") VALUES ('cmnd2zfr3000by3373mos15cr', 'Tender No: 0112-2026', 'tender-no-0112-2026', 'NAGECO invites qualified companies to participate in Tender No: 0112-2026 for the provision of geophysical exploration services. The scope of work includes field data acquisition, processing, and interpretation in accordance with international standards. Interested bidders are required to submit their technical and commercial proposals within the specified deadline.', 'PUBLISHED', '2026-03-30 11:11:49.818', '2026-03-30 11:04:36.735', '2026-03-30 11:11:49.821', 'cmmd40kqs0000qvmfkhfexsk3', 'cmmd40kqs0000qvmfkhfexsk3', '{/uploads/1774868655942-e68834f7-a693-41e0-8b2f-31d9d08da903.docx,/uploads/1774869106487-5b8bb3fe-5a38-4279-ba79-cf524d75ca3a.pdf}', '{/uploads/1774868581437-b3837075-144d-4bb2-b01e-8be28bb1a005.JPG,/uploads/1774868581883-a6172244-b1a1-4148-a2f6-eedbf39ec1bd.JPG,/uploads/1774868581957-0952af93-ab4c-454f-a7d9-7fe7566fbb5f.JPG,/uploads/1774868582041-1d23d2e4-d595-41a9-b3ac-3b59d72d46c4.JPG}');
